SELECT s.brand_name, SUM(s.shipped_units) AS shipped_units, SUM(c.conceded_units) AS conceded_units, (SUM(c.conceded_units) * 100.0) / NULLIF(SUM(s.shipped_units), 0) AS return_rate_pct FROM shipped_raw s JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.brand_name IS NOT NULL GROUP BY s.brand_name HAVING SUM(s.shipped_units) > 0 ORDER BY return_rate_pct DESC LIMIT 10;